/// <summary>
/// Asset book import
/// </summary>

public class ETG_Acu_AssetBookImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_AssetBookImport  assetBookImport;

    assetBookImport = ETG_Acu_AssetBookImport::construct();

    if (assetBookImport.prompt())
    {
        assetBookImport.runOperation();
    }
}

public static ETG_Acu_AssetBookImport construct()
{
    return new ETG_Acu_AssetBookImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    AssetBookV2Entity   assetBook;
    AssetId             assetId;
    AssetBookId         assetBookId;

    assetId     =   conpeek(_con, 1);
    assetBookId =   conPeek(_con, 2);

    select firstonly forupdate assetBook
        where assetBook.FixedAssetNumber == assetId
            && assetBook.BookId ==  assetBookId;

    if (!assetBook)
    {
        assetBook.FixedAssetNumber              =   conpeek(_con, 1);
        assetBook.BookId                        =   conpeek(_con, 2);
        assetBook.DepreciationPeriods           =   conpeek(_con, 3);
        assetBook.DepreciationPeriodsRemaining  =   conpeek(_con, 4);
        assetBook.DepreciationProfileId         =   conpeek(_con, 5);
        assetBook.ExpectedScrapValue            =   conpeek(_con, 6);
        assetBook.FixedAssetGroupId             =   conpeek(_con, 7);
        assetBook.PostingProfileId              =   conpeek(_con, 8);
        assetBook.ServiceLife                   =   conpeek(_con, 9);
        assetBook.DepreciationRunDate           =   str2Date(conpeek(_con, 10),123);
        assetBook.PlacedInService               =   str2Date(conpeek(_con, 11),123);
        assetBook.AcquisitionDate               =   str2Date(conpeek(_con, 12),123);
        assetBook.insert();
    }
    else
    {
        assetBook.DepreciationPeriods           =   conpeek(_con, 3);
        assetBook.DepreciationPeriodsRemaining  =   conpeek(_con, 4);
        assetBook.DepreciationProfileId         =   conpeek(_con, 5);
        assetBook.ExpectedScrapValue            =   conpeek(_con, 6);
        assetBook.FixedAssetGroupId             =   conpeek(_con, 7);
        assetBook.PostingProfileId              =   conpeek(_con, 8);
        assetBook.ServiceLife                   =   conpeek(_con, 9);
        assetBook.DepreciationRunDate           =   str2Date(conpeek(_con, 10),123);
        assetBook.PlacedInService               =   str2Date(conpeek(_con, 11),123);
        assetBook.AcquisitionDate               =   str2Date(conpeek(_con, 12),123);
        assetBook.update();
    }
}

/// <summary>
///Import asset book
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "Import asset book";

    return ret;
}
